let currentSlide = 0;
const slides = document.querySelectorAll('.slide');
const progressBar = document.getElementById('bar');

function updateProgress() {
    // Slides ki total counting ke hisaab se bar ko update karein
    const percent = ((currentSlide + 1) / slides.length) * 100;
    progressBar.style.width = percent + "%";
}

function next() {
    if (currentSlide < slides.length - 1) {
        // Purani slide se 'active' class hatao
        slides[currentSlide].classList.remove('active');

        // Agli slide par jao
        currentSlide++;

        // Nayi slide ko 'active' karo
        slides[currentSlide].classList.add('active');

        // Progress bar ko update karo
        updateProgress();
    }
}

// Pehli baar load hone par bar set karein
updateProgress();
const canvas = document.getElementById('heartCanvas');
const ctx = canvas.getContext('2d');

// Screen size ke mutabiq canvas set karna
function resize() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
}
window.addEventListener('resize', resize);
resize();

const hearts = [];

// Dil (Heart) banane ka function
function createHeart() {
    hearts.push({
        x: Math.random() * canvas.width,
        y: canvas.height + 50,
        size: Math.random() * 15 + 10,
        speed: Math.random() * 2 + 1,
        opacity: Math.random() * 0.5 + 0.3
    });
}

// Dil ko screen par dikhane ka function
function drawHearts() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    hearts.forEach((heart, index) => {
        heart.y -= heart.speed;
        ctx.globalAlpha = heart.opacity;
        ctx.fillStyle = '#ff4d6d'; // Pyara sa Pinkish Red color

        // Heart Shape drawing
        ctx.beginPath();
        ctx.moveTo(heart.x, heart.y);
        ctx.bezierCurveTo(heart.x - heart.size/2, heart.y - heart.size/2, heart.x - heart.size, heart.y + heart.size/3, heart.x, heart.y + heart.size);
        ctx.bezierCurveTo(heart.x + heart.size, heart.y + heart.size/3, heart.x + heart.size/2, heart.y - heart.size/2, heart.x, heart.y);
        ctx.fill();

        // Agar dil screen se bahar nikal jaye toh delete kar do
        if (heart.y < -50) hearts.splice(index, 1);
    });

    requestAnimationFrame(drawHearts);
}

// Har 300ms baad ek naya dil banega
setInterval(createHeart, 300);
drawHearts();

style.css:
:root {
    /* Pure Valentine Red & Luxury Gold Theme */
    --valentine-red: #d00000;
    --deep-maroon: #4a0000;
    --gold-accent: #ffd700;
    --bg-dark: #120000; /* Darker Redish Black */
}

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
    background: radial-gradient(circle, #2b0000 0%, var(--bg-dark) 100%);
    font-family: 'Poppins', sans-serif;
    color: white;
    height: 100vh;
    overflow: hidden;
}

#heartCanvas {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    z-index: -1; /* Isse hearts background par chale jayenge */
    pointer-events: none;
}

/* Progress Bar in Red/Gold */
.progress-container {
    position: fixed;
    top: 0; left: 0; width: 100%; height: 6px;
    background: rgba(255,255,255,0.1);
    z-index: 100;
}
.progress-bar {
    height: 100%;
    width: 0%;
    background: linear-gradient(to right, var(--valentine-red), var(--gold-accent));
    box-shadow: 0 0 15px var(--valentine-red);
    transition: width 0.4s ease;
}

.slider {
    position: relative;
    height: 100vh;
    width: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 10;
}

.slide {
    position: absolute;
    opacity: 0;
    transform: scale(0.9) translateY(30px);
    transition: all 0.8s cubic-bezier(0.4, 0, 0.2, 1);
    pointer-events: none;
    text-align: center;
}

.slide.active {
    opacity: 1;
    transform: scale(1) translateY(0);
    pointer-events: all;
}

.glass-card {
    background: rgba(255, 255, 255, 0.05);
    backdrop-filter: blur(25px);
    border: 1px solid rgba(212, 175, 55, 0.3); /* Gold border hint */
    padding: 3.5rem;
    border-radius: 40px;
    max-width: 500px;
    width: 90%;
    box-shadow: 0 20px 50px rgba(0,0,0,0.7), inset 0 0 20px rgba(208, 0, 0, 0.2);
}

.emoji { 
    font-size: 55px; 
    display: block; 
    margin-bottom: 15px; 
    filter: drop-shadow(0 0 10px var(--valentine-red));
}

h1, h2 {
    font-family: 'Dancing Script', cursive;
    margin-bottom: 20px;
    letter-spacing: 2px;
}

.neon-text {
    color: #fff;
    text-shadow: 0 0 10px var(--valentine-red), 0 0 20px var(--valentine-red), 0 0 30px var(--valentine-red);
}

p { font-size: 1.15rem; line-height: 1.8; color: #f0f0f0; margin-bottom: 30px; font-weight: 300; }

.big-text { font-size: 2rem; font-weight: bold; color: var(--gold-accent); }

/* Buttons in Red */
button {
    background: transparent;
    border: 2px solid var(--valentine-red);
    padding: 12px 40px;
    color: white;
    border-radius: 50px;
    cursor: pointer;
    font-weight: 600;
    transition: 0.3s;
    text-transform: uppercase;
    letter-spacing: 1px;
}

button:hover {
    background: var(--valentine-red);
    box-shadow: 0 0 30px var(--valentine-red);
    transform: translateY(-3px);
}

.neon-btn {
    background: var(--valentine-red);
    border: none;
    box-shadow: 0 0 20px rgba(208, 0, 0, 0.6);
}

.footer-line {
    font-size: 0.9rem;
    color: var(--gold-accent);
    margin-bottom: 20px;
    font-style: italic;
}
@media (max-width: 600px) {
    .glass-card {
        padding: 1.5rem; /* Mobile par padding kam kar di */
        border-radius: 25px;
    }
    h2 { font-size: 1.5rem; }
    p { font-size: 1rem; line-height: 1.5; }
    .emoji { font-size: 40px; }
}
